B.a4t=new A.aG("Neyin do\u011fru neyin yanl\u0131\u015f oldu\u011funu hisseden, kusursuzu hayal eden, yanl\u0131\u015f olan \u015fey d\xfczeltilene kadar dinlenmeden \xe7abalayan bir yap\u0131ya sahibim.")
B.a3W=new A.aG("Duygusal, ili\u015fkilerini \xe7ok \xf6nemseyen, sevgiye \xe7ok de\u011fer veren, cana yak\u0131n, yard\u0131msever, \xe7abuk ve kolay ileti\u015fim kurabilen bir yap\u0131ya sahibim.")
B.a4l=new A.aG("Ba\u015far\u0131l\u0131 ve etkileyici olmaktan ho\u015flanan, stat\xfc ve g\xf6r\xfcn\xfcm\xfc \xf6nemseyen, h\u0131rsl\u0131, enerjik ve rekabet\xe7i bir yap\u0131ya sahibim.")
B.a45=new A.aG("Hassas, empati kurmay\u0131 \xf6nemseyen, \xf6zg\xfcnl\xfc\u011fe ve bireyselli\u011fe \xe7ok \xf6nem veren, ya\u015fad\u0131klar\u0131 ve hissettikleri \xfczerinde derinlemesine d\xfc\u015f\xfcnen bir yap\u0131ya sahibim.")
B.a4k=new A.aG("Bilgiye ve ara\u015ft\u0131rmaya merakl\u0131, yaln\u0131z kalmaktan rahats\u0131z olmayan, kendini ve olaylar\u0131 duygulardan ba\u011f\u0131ms\u0131z olarak g\xf6zlemleyip rasyonel ve nesnel analiz yapmaya e\u011filimli bir yap\u0131ya sahibim.")
B.a4B=new A.aG("G\xfcven ve emniyet i\xe7inde hissetmeyi \xe7ok \xf6nemseyen, tedbirli, merakl\u0131, sorgulay\u0131c\u0131, riskleri hesaplayabilen ve her zaman B plan\u0131 bulunduran bir yap\u0131ya sahibim.")
B.a4q=new A.aG("Ke\u015ffetmeyi ve yeni \u015feyler deneyimlemeyi seven, mant\u0131\u011f\u0131yla hareket eden, duygulara tak\u0131lmayan, iyimser, merakl\u0131, d\u0131\u015fa d\xf6n\xfck, ne\u015feli, konu\u015fkan ve giri\u015fken bir yap\u0131ya sahibim.")
B.a4z=new A.aG("Cesur, kararl\u0131, otoriter, insanlar\u0131 etkilemeyi seven, g\xfc\xe7l\xfc ve ba\u011f\u0131ms\u0131z olmay\u0131 \xf6nemseyen, risk almaktan \xe7ekinmeyen, zorluklara kar\u015f\u0131 dayan\u0131kl\u0131, m\xfccadeleden ve \xe7at\u0131\u015fmadan ka\xe7\u0131nmayan bir yap\u0131ya sahibim.")
B.a4g=new A.aG("Huzuru arayan, sab\u0131rl\u0131, sakin, gerilimden ka\xe7\u0131nan, sosyal ortamlarda g\xf6rmezden gelinmekten ho\u015flanmayan ancak \xf6ne \xe7\u0131kmay\u0131 da pek tercih etmeyen bir yap\u0131ya sahibim.")
B.UP=s([B.a4t,B.a3W,B.a4l,B.a45,B.a4k,B.a4B,B.a4q,B.a4z,B.a4g],t.DC)
B.aim=new A.aky(0,"matrix")
B.a4R=new A.j3("Kendinizi Nas\u0131l Tan\u0131mlars\u0131n\u0131z?",B.UP)
B.a4H=new A.aG("Hayata bak\u0131\u015f a\xe7\u0131m daha \xe7ok esner.")
B.a4J=new A.aG("Kendimle vakit ge\xe7irmenin keyfini \xe7\u0131kart\u0131r\u0131m.")
B.a3U=new A.aG("Duygulara kar\u015f\u0131 ilgim ve alakam artar.")
B.a4E=new A.aG("Ya\u015fam\u0131mda kendimle ilgili rutinlerin say\u0131s\u0131 artar.")
B.a3V=new A.aG("Anlatt\u0131\u011f\u0131m konularda daha iddial\u0131 olurum.")
B.a4j=new A.aG("Belirsizlikleri kabul etme ihtimalim artar.")
B.a3R=new A.aG("\u0130lgilenmem gereken i\u015flere kar\u015f\u0131 oda\u011f\u0131m artar.")
B.a4m=new A.aG("Empati yapar, duygular\u0131m\u0131 rahat\xe7a g\xf6steririm.")
B.a49=new A.aG("Fikirlerimi \xe7ekinmeden ifade ederim.")
B.RV=s([B.a4H,B.a4J,B.a3U,B.a4E,B.a3V,B.a4j,B.a3R,B.a4m,B.a49],t.DC)
B.a4O=new A.j3("Her \u015feyin yolunda gitti\u011fi, mutlu ve rahat bir ya\u015fam s\xfcrecinde kendinizde g\xf6zlemledi\u011finiz de\u011fi\u015fiklikler neler olur?",B.RV)
B.a4y=new A.aG("Benimle birlikte geli\u015fecek ve geli\u015fimime katk\u0131 sa\u011flayacak bir ili\u015fki beklerim.")
B.a48=new A.aG("Sevildi\u011fim ve sevece\u011fim i\xe7ten bir ba\u011f beklerim.")
B.a3M=new A.aG("Takdir g\xf6rd\xfc\u011f\xfcm, \xf6rnek olacak bir ili\u015fki beklerim.")
B.a4w=new A.aG("Sayg\u0131n, derinlikli duygusal yak\u0131nl\u0131kta bir ili\u015fki beklerim.")
B.a4h=new A.aG("S\u0131n\u0131rlar\u0131na sayg\u0131 duyulan, ufuk a\xe7\u0131c\u0131 bir ili\u015fki beklerim.")
B.a3H=new A.aG("Yarg\u0131lanmadan konu\u015fuldu\u011fu, sadakat temelli bir ili\u015fki beklerim.")
B.a4p=new A.aG("Enerjik, mizah\u0131 y\xfcksek, konu\u015ftu\u011fumun hemen anla\u015f\u0131ld\u0131\u011f\u0131 bir ili\u015fki beklerim.")
