B.a_u=new A.S(B.fU,["\ud83c\udfa4","Seminer","Enneagram ve miza\xe7 tiplerini derinlemesine ele alan, kurumsal veya bireysel gruplara y\xf6nelik interaktif seminerler.","Grup dinamiklerini g\xfc\xe7lendirmek, ekip uyumunu art\u0131rmak veya bireysel fark\u0131ndal\u0131k kazanmak isteyen herkese uygundur."],t.w)
B.a_q=new A.S(B.fU,["\ud83d\udd0e","Analiz","Test sonu\xe7lar\u0131n\u0131n uzman g\xf6z\xfcyle de\u011ferlendirildi\u011fi, ki\u015finin temel miza\xe7 yap\u0131s\u0131n\u0131 b\xfct\xfcn\xfcyle ortaya koyan profesyonel analiz.","Temel tip, kanat etkisi ve alt tip bir arada de\u011ferlendirilerek ki\u015fiye \xf6zel i\xe7g\xf6r\xfcler sunulur."],t.w)
B.a_s=new A.S(B.fU,["\ud83d\udcc4","Raporlama","Analiz sonu\xe7lar\u0131n\u0131n kapsaml\u0131 ve okunabilir bi\xe7imde sunuldu\u011fu, ki\u015fisel geli\u015fim yolculu\u011funa rehberlik eden yaz\u0131l\u0131 raporlar.","G\xfc\xe7l\xfc y\xf6nler, geli\u015fim alanlar\u0131 ve \xf6nerilen ad\u0131mlar\u0131 i\xe7eren detayl\u0131 raporlar dijital veya bas\u0131l\u0131 olarak teslim edilir."],t.w)
B.a_t=new A.S(B.fU,["\ud83e\udd1d","Dan\u0131\u015fmanl\u0131k","Birebir online veya y\xfcz y\xfcze ger\xe7ekle\u015ftirilen, miza\xe7 odakl\u0131 ki\u015fisel geli\u015fim ve kariyer y\xf6nelimi dan\u0131\u015fmanl\u0131\u011f\u0131.","D\xfczenli seanslarda miza\xe7 tipinizin sizi nas\u0131l \u015fekillendirdi\u011fini ke\u015ffeder, sa\u011fl\u0131kl\u0131 \xf6r\xfcnt\xfcler geli\u015ftirme yolculu\u011funa \xe7\u0131kars\u0131n\u0131z."],t.w)
B.a_r=new A.S(B.fU,["\ud83d\udee0\ufe0f","At\xf6lyeler","K\xfc\xe7\xfck gruplara \xf6zel, uygulamal\u0131 egzersizler ve grup dinamikleriyle zenginle\u015ftirilen Enneagram ke\u015fif at\xf6lyeleri.","Teorik bilgiyi ya\u015fayarak \xf6\u011frenmek isteyenler i\xe7in tasarlanm\u0131\u015f, interaktif ve deneyimsel \xf6\u011frenme ortamlar\u0131."],t.w)
